import React from "react";
import { Button } from "@/components/ui/button";
import { Link } from "react-router-dom";

interface FullBleedHeroProps {
  title: string;
  subtitle?: string;
  image: string;
  alt: string;
  primaryLabel?: string;
  primaryHref?: string;
  primaryOnClick?: () => void;
  secondaryLabel?: string;
  secondaryHref?: string;
  secondaryOnClick?: () => void;
  secondaryClass?: string;
  imageFit?: "cover" | "contain";
  id?: string;
  children?: React.ReactNode;
}

const isExternal = (href: string) => href.startsWith("http") || href.startsWith("tel:") || href.startsWith("mailto:");

const FullBleedHero: React.FC<FullBleedHeroProps> = ({
  title,
  subtitle,
  image,
  alt,
  primaryLabel,
  primaryHref,
  primaryOnClick,
  secondaryLabel,
  secondaryHref,
  secondaryOnClick,
  secondaryClass,
  imageFit = "cover",
  id,
  children,
}) => {
  return (
    <section id={id} className="relative isolate overflow-hidden">
      <img
        src={image}
        alt={alt}
        loading="eager"
        className={`absolute inset-0 -z-10 w-full h-full object-${imageFit}`}
      />
      <div className="absolute inset-0 -z-10 bg-gradient-to-t from-background/90 via-background/50 to-transparent" />

      <div className="container mx-auto px-4 flex items-end min-h-[40vh] sm:min-h-[55vh] md:min-h-[65vh] lg:min-h-[75vh] py-10 sm:py-16 md:py-24 lg:py-28">
        <div className="max-w-3xl">
            <h1 className="font-heading text-2xl sm:text-3xl md:text-4xl lg:text-5xl xl:text-6xl font-extrabold mb-4 leading-tight">
              {title}
            </h1>
            {subtitle && (
              <p className="text-sm sm:text-base md:text-lg lg:text-xl text-muted-foreground mb-6 md:mb-8 leading-relaxed">
                {subtitle}
              </p>
            )}
          <div className="flex flex-col sm:flex-row gap-3">
            {primaryLabel && (primaryHref || primaryOnClick) && (
              primaryOnClick ? (
                <Button size="lg" variant="hero" className="px-8 py-3" onClick={primaryOnClick}>
                  {primaryLabel}
                </Button>
              ) : (
                <Button asChild size="lg" variant="hero" className="px-8 py-3">
                  {isExternal(primaryHref!) ? (
                    <a href={primaryHref}>{primaryLabel}</a>
                  ) : (
                    <Link to={primaryHref!}>{primaryLabel}</Link>
                  )}
                </Button>
              )
            )}
            {secondaryLabel && (secondaryHref || secondaryOnClick) && (
              secondaryOnClick ? (
                <Button size="lg" variant="accent" className="px-8 py-3" onClick={secondaryOnClick}>
                  {secondaryLabel}
                </Button>
              ) : (
                <Button asChild size="lg" variant="accent" className="px-8 py-3">
                  {isExternal(secondaryHref!) ? (
                    <a href={secondaryHref}>{secondaryLabel}</a>
                  ) : (
                    <Link to={secondaryHref!}>{secondaryLabel}</Link>
                  )}
                </Button>
              )
            )}
          </div>
          {children ? <div className="mt-4">{children}</div> : null}
        </div>
      </div>
    </section>
  );
};

export default FullBleedHero;
